__kernel void dynproc_kernel(
    int arg0,
    __global const int* d_gpuWall,
    __global const int* src,
    __global int* dst,
    int cols,
    int rows,
    int t,
    int borderCols,
    int theHalo,
    __local int* local_src,
    __local int* local_dst,
    __global int* d_outputBuffer)
{
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int lsize = get_local_size(0);

    // Initialize local memory
    if (gid < cols) {
        local_src[lid] = src[gid];
    } else {
        local_src[lid] = 2147483647; // INT_MAX approximation
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (gid >= cols) return;

    int min_val = local_src[lid];

    // Check left neighbor
    if (lid > 0) {
        int left = local_src[lid - 1];
        if (left < min_val) min_val = left;
    }

    // Check right neighbor
    if (lid < cols - 1) {
        int right = (lid + 1 < lsize) ? local_src[lid + 1] : 2147483647;
        if (gid < cols - 1) {
            // If we are not at the boundary of the data, check actual right neighbor
            if (lid + 1 < cols || gid < cols - 1) {
                int r_val = (lid + 1 < cols) ? local_src[lid + 1] : src[gid + 1];
                if (r_val < min_val) min_val = r_val;
            }
        }
    }

    // Re-evaluate neighbors directly from global memory to handle cross-block boundaries correctly
    // Since the original code does a simple 1D pass, we must ensure n-1 and n+1 are checked globally
    int n = gid;
    int current_min = src[n];

    if (n > 0) {
        int left_val = src[n-1];
        if (left_val < current_min) current_min = left_val;
    }

    if (n < cols - 1) {
        int right_val = src[n+1];
        if (right_val < current_min) current_min = right_val;
    }

    // Calculate wall index: wall[t+1][n]
    // d_gpuWall starts from data + cols (row 1 onwards)
    // Row t+1 corresponds to index (t+1)*cols + n in original data
    // But d_gpuWall is passed as (data + cols), so row 1 is at offset 0
    // Row t+1 is at offset (t)*cols in d_gpuWall
    int wall_idx = t * cols + n;

    dst[n] = d_gpuWall[wall_idx] + current_min;
}
